svg.script:
const urlParams = new URLSearchParams(window.location.search);
const shortId = urlParams.get('meow') || 'NUGGET';

let itemsData = {};
let badgesMap = {};
const skinValueCache = new Map();

function esc(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;').replace(/'/g,'&#39;');
}

function fmtShort(num) {
  if (num == null) return '0';
  if (num >= 1_000_000) return (num/1_000_000).toFixed(1)+'M';
  if (num >= 1_000) return (num/1_000).toFixed(1)+'K';
  return String(num);
}

function fmtValue(val) {
  if (!val && val !== 0) return 'N/A';
  const n = parseFloat(val);
  if (isNaN(n)) return String(val);
  if (n >= 1_000_000_000) return (n/1_000_000_000).toFixed(2)+'B';
  if (n >= 1_000_000) return (n/1_000_000).toFixed(2)+'M';
  if (n >= 1_000) return (n/1_000).toFixed(1)+'K';
  return String(n);
}

function getSkinItem(skin) {
  if (!skin) return null;
  return itemsData[skin.id] || itemsData[(skin.name||'').toLowerCase()] || null;
}

async function main() {
  try {
    const [skins, badges, profileRes] = await Promise.all([
      fetch('https://raw.githubusercontent.com/OBS-Akuma/KirkaSkins/refs/heads/main/AllItemData.json').then(r=>r.json()).catch(()=>[]),
      fetch('https://raw.githubusercontent.com/OBS-Akuma/KirkaBadges/refs/heads/main/Json/badge.json').then(r=>r.json()).catch(()=>[]),
      fetch('https://www.smudgy.store/api/getprofile',{
        method:'POST',
        headers:{'Content-Type':'application/json'},
        body:JSON.stringify({userId:`#${shortId}`,isShortId:true})
      }).then(r=>r.json())
    ]);

    (Array.isArray(skins)?skins:[]).forEach(item=>{
      if(item.id) itemsData[item.id]=item;
      if(item.name) itemsData[item.name.toLowerCase()]=item;
    });

    const entries = Array.isArray(badges)?badges:Object.values(badges);
    entries.forEach(e=>{ if(e?.shortId) badgesMap[e.shortId.toUpperCase()]=e; });

    if (!profileRes.success || !profileRes.data) throw new Error('Profile not found');

    const d = profileRes.data;
    const badge = badgesMap[(d.shortId||'').toUpperCase()] || null;

    let invValue = null, invLoading = true;
    try {
      const invRes = await fetch('https://www.smudgy.store/api/getinventory',{
        method:'POST',
        headers:{'Content-Type':'application/json'},
        body:JSON.stringify({userId:`#${shortId}`,isShortId:true})
      });
      const invData = await invRes.json();
      if (invData.success && invData.data?.length) {
        const items = invData.data;
        const uniqueNames = [...new Set(items.map(i=>i.item.name))];
        const uncached = uniqueNames.filter(n=>!skinValueCache.has(n.toLowerCase()));
        if (uncached.length > 0) {
          const priceRes = await fetch(`https://www.smudgy.store/api/pricecalc?price=${encodeURIComponent(uncached.join(','))}`);
          const priceData = await priceRes.json();
          if (priceData.breakdown) {
            for(const [name,val] of Object.entries(priceData.breakdown)) skinValueCache.set(name.toLowerCase(), val);
          }
        }
        let total = 0;
        items.forEach(item=>{ total += (skinValueCache.get(item.item.name.toLowerCase())||0) * (item.amount||1); });
        invValue = total;
      }
      invLoading = false;
    } catch(e) { invLoading = false; }

    const xpPct = d.xpUntilNextLevel ? Math.min(100,(d.xpSinceLastLevel/d.xpUntilNextLevel)*100) : 0;
    const bodySkinItem = getSkinItem(d.activeBodySkin);
    const avatarRender = bodySkinItem?.renderUrl || null;
    const invDisplay = invLoading ? '...' : fmtValue(invValue);

    const discordBadge = d.discord ? 'https://raw.githubusercontent.com/OBS-Akuma/KirkaSkins/refs/heads/main/img/linked.webp' : null;
    let badgesList = [...(badge?.badges || [])];
    if (discordBadge) badgesList.push(discordBadge);

    let usernameGradientStyle = '';
    if (badge?.gradient) {
      const stops = badge.gradient.stops.join(', ');
      const rot = badge.gradient.rot || '90deg';
      usernameGradientStyle = `background: linear-gradient(${rot}, ${stops}); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;`;
      document.querySelector('.name').style = usernameGradientStyle;
    }

    if (avatarRender) {
      document.querySelector('.avatar').innerHTML = `<img src="${esc(avatarRender)}" alt="avatar"/>`;
    } else {
      document.querySelector('.avatar').innerHTML = `<span>${esc(d.name?.[0]?.toUpperCase()||'?')}</span>`;
    }

    document.getElementById('username').innerHTML = esc(d.name.length > 15 ? d.name.substring(0, 12) + '...' : d.name);
    document.getElementById('shortid').innerHTML = esc(d.shortId);
    document.getElementById('level').innerHTML = d.level||0;
    document.getElementById('xp-fill').style.width = xpPct + '%';
    document.getElementById('klo').innerHTML = d.klo?.toFixed(0)||0;
    document.getElementById('coins').innerHTML = fmtShort(d.coins);
    document.getElementById('diamonds').innerHTML = d.diamonds||0;
    document.getElementById('inv-value').innerHTML = invDisplay;
    document.getElementById('views').innerHTML = (d.viewCount||0) + ' views';

    if (d.clan) {
      document.getElementById('clan').innerHTML = esc(d.clan);
    }

    const badgesContainer = document.getElementById('badges');
    badgesContainer.innerHTML = badgesList.map(url => `<img class="badge-icon" src="${esc(url)}"/>`).join('');

  } catch(err) {
    console.error(err);
  }
}
main();
